SELECT DISTINCT
    at.at_activity_code AS value,
    UPPER(
        CONCAT_WS(
            ' - ',
            at.at_activity_code,
            at.at_activity_description_bm
        )
    ) AS label
FROM
    org_unit_costcentre ouc,
    activity_type at
WHERE ouc.at_activity_code = at.at_activity_code
    and (
        ouc.fty_fund_type = {Fund}
        or {Fund} is null
    )
    and (
        ouc.oun_code = {PTJ}
        or {PTJ} is null
    )
    and (
        ouc.ccr_costcentre = {CostCentre}
        or {CostCentre} is null
    )
ORDER BY
    at.at_activity_code;

